class Solution:
    def maximumRemovals(self, s, p, removable):
        # Independent: linear scan increasing k, rebuilding the removed set each time but stop early.
        n = len(s)
        def ok(k):
            removed = [False] * n
            for i in range(k):
                removed[removable[i]] = True
            j = 0
            for i in range(n):
                if removed[i]:
                    continue
                if j < len(p) and s[i] == p[j]:
                    j += 1
            return j == len(p)
        # linear is fine for stress sizes (n<=600), test descending and return first ok
        for k in range(len(removable), -1, -1):
            if ok(k):
                return k
        return 0

