class Solution:
    def maximumRemovals(self, s, p, removable):
        n = len(s)
        def ok(k):
            removed = [False] * n
            for i in range(k):
                removed[removable[i]] = True
            j = 0
            m = len(p)
            for i in range(n):
                if removed[i]:
                    continue
                if j < m and s[i] == p[j]:
                    j += 1
                    if j == m:
                        return True
            return j == m
        lo, hi = 0, len(removable)
        ans = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if ok(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

