var maximumRemovals = function(s, p, removable) {
    const n = s.length, m = p.length;
    const ok = (k) => {
        const removed = new Uint8Array(n);
        for (let i = 0; i < k; i++) removed[removable[i]] = 1;
        let j = 0;
        for (let i = 0; i < n; i++) {
            if (removed[i]) continue;
            if (j < m && s[i] === p[j]) {
                j++;
                if (j === m) return true;
            }
        }
        return j === m;
    };
    let lo = 0, hi = removable.length, ans = 0;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (ok(mid)) { ans = mid; lo = mid + 1; }
        else hi = mid - 1;
    }
    return ans;
};
